package com.vidaysalud.veterinaria.veterinarioservicio.model; import jakarta.persistence.*; import lombok.*; @Entity @Table(name="veterinario",uniqueConstraints=@UniqueConstraint(name="uq_veterinario_email",columnNames="email")) @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class Veterinario{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="id_veterinario") private Integer idVeterinario; @Column(nullable=false,length=100) private String nombre; @Column(nullable=false,length=100) private String especialidad; @Column(length=20) private String telefono; @Column(length=100,unique=true) private String email; @Column(nullable=false) private Boolean activo; @PrePersist void pre(){if(activo==null)activo=true;}}